import React, { useState, useEffect } from 'react';
import { useCart } from '../context/CartContext';
import CartToast from '../components/CartToast';
import QuickViewModal from '../components/QuickViewModal';

// Brand logos
import jamxImg   from '../assets/images/jamk.png';
import digitek   from '../assets/images/digitek.png';
import tekReact  from '../assets/images/tek reactjs.png';
import grafbase  from '../assets/images/grafbase.png';
import msiImg    from '../assets/images/msi.png';
import ohbear    from '../assets/images/ohbear.png';
import oak       from '../assets/images/oak.png';
import snyk      from '../assets/images/snyk.png';
import sonex     from '../assets/images/sonex.png';
import stropi    from '../assets/images/stropi.png';

// Top category icons
import laptopImg      from '../assets/images/laptop.png';
import pcGamingImg    from '../assets/images/pc gaming.png';
import headphones     from '../assets/images/headphones.png';
import monitorsImg    from '../assets/images/monitors.png';
import topCellphoneImg from '../assets/images/top cellphone.png';

// Best Seller products
import boso2Img    from '../assets/images/boso2 wireless.png';
import opodProImg  from '../assets/images/opod pro12.png';
import uluskImg    from '../assets/images/ulusk mini.png';
import oppoloWatch from '../assets/images/oppolo watch.png';
import ismartImg   from '../assets/images/ismart 24v.png';

// Brand New For You banners
import zumacImg    from '../assets/images/zumac.png';
import microsute   from '../assets/images/microsute.png';
import gamingChair from '../assets/images/gaming chair.png';
import ipedImg     from '../assets/images/iped .png';

// Hero section images
import noiseCancelImg  from '../assets/images/noise cancelling headphone.png';
import sonoPlaygoImg   from '../assets/images/xiamoi.png';
import logitekImg      from '../assets/images/logiket bluetooth keyboard.png';
import xomiaWatchImg   from '../assets/images/sports water watch.png';
import okodoHeroImg    from '../assets/images/okodo hero black.png';

// Deals of the day
import xiaomiImg   from '../assets/images/xioma redmi.png';
import joystickImg from '../assets/images/joystick.png';
import ipadImg     from '../assets/images/ipad.png';

// Cell phone products
import srokImg     from '../assets/images/xiamoi.png';
import apodImg     from '../assets/images/opod pro12.png';
import opodImg     from '../assets/images/opod pro.png';
import xiaomiNote5 from '../assets/images/xioma redmi.png';
import microsuteSurf from '../assets/images/microsute.png';

// Best Laptops
import bestLaptopImg from '../assets/images/best laptop.png';

import './CategoriesPage.css';

const brands = [
  { img: jamxImg,  name: 'JAMX'     },
  { img: digitek,  name: 'Digitek'  },
  { img: tekReact, name: 'TekReact' },
  { img: grafbase, name: 'Grafbase' },
  { img: msiImg,   name: 'MSI'      },
  { img: ohbear,   name: 'OhBear'   },
  { img: oak,      name: 'OAK'      },
  { img: snyk,     name: 'Snyk'     },
  { img: sonex,    name: 'Sonex'    },
  { img: stropi,   name: 'Stropi'   },
];

const topCategories = [
  { img: laptopImg,   name: 'Laptops'    },
  { img: pcGamingImg, name: 'PC Gaming'  },
  { img: headphones,  name: 'Headphones' },
  { img: monitorsImg, name: 'Monitors'   },
];

const bestSellerProducts = [
  { id: 'bs1', img: boso2Img,   name: 'BOSO 2 Wireless On Ear Headphone',                    price: '$359.00', save: '$199.00', reviews: 152, shipping: 'FREE SHIPPING', gift: 'FREE GIFT', stock: 'In stock',     variants: [boso2Img, headphones] },
  { id: 'bs2', img: opodProImg, name: 'OPod Pro 12.9 Inch M1 2023, 64GB + Wifi, GPS',        price: '$569.00', oldPrice: '$759.00', save: '$199.00', reviews: 152, shipping: 'FREE SHIPPING', stock: 'In stock' },
  { id: 'bs3', img: uluskImg,   name: 'uLosk Mini case 2.0, Xenon i10 / 32GB / SSD 512GB / VGA 8GB', price: '$1,729.00', oldPrice: '$2,119.00', save: '$59.00', reviews: 8, shipping: 'FREE SHIPPING', stock: 'Out of stock' },
  { id: 'bs4', img: oppoloWatch,name: 'Opplo Watch Series 8 GPS + Cellular Stainless Steel Case with Milanese Loop', price: '$979.00 - $1,259.00', reviews: null, shipping: '$2.98 SHIPPING', stock: 'PRE - ORDER' },
  { id: 'bs5', img: ismartImg,  name: 'iSmart 24V Charger',                                  price: '$9.00', oldPrice: '$12.00', save: '$3.00', reviews: 9, shipping: '$3.98 SHIPPING', stock: 'Contact' },
];

const brandNewItems = [
  { img: zumacImg,    title: 'Zumac Steel Computer Case',                          desc: 'And an option to upgrade every three years' },
  { img: microsute,   title: 'Summer Sale with Sale up to 50% OFF for Foam Gaming Chair.', desc: 'Limited time offer. Hurry up' },
  { img: gamingChair, title: 'Summer Sale with Sale up to 50% OFF for Foam Gaming Chair.', desc: 'Limited time offer. Hurry up' },
  { img: ipedImg,     title: 'iPed Pro Mini 6 - Powerful I in hand',               desc: 'From $19.99/month for 36 months. $280.35 final payment due in month 37' },
];

const cellPhoneProducts = [
  { id: 'cp1', img: srokImg,      name: 'SROK Smart Phone 128GB, Oled Retina',                        price: '$579.00', oldPrice: '$859.00', save: '$199.00', shipping: 'FREE SHIPPING', stock: 'In stock' },
  { id: 'cp2', img: apodImg,      name: 'aPod Pro Tablet 2023 LTE + Wifi, GPS Cellular 12.9 Inch, 512GB', price: '$979.00 - $1,259.00', shipping: '$2.98 SHIPPING', stock: 'In stock', badge: 'NEW' },
  { id: 'cp3', img: opodImg,      name: 'OPod Pro 12.9 Inch M1 2023, 64GB + Wifi, GPS',              price: '$659.00', shipping: 'FREE SHIPPING', gift: 'FREE GIFT', stock: 'In stock', save: '$59.00' },
  { id: 'cp4', img: xiaomiNote5,  name: 'Xiaomi Redmi Note 5, 64GB',                                  price: '$1,239.00', oldPrice: '$1,619.00', shipping: 'FREE SHIPPING', stock: 'Contact' },
  { id: 'cp5', img: microsuteSurf,name: 'Microsute Alpha Ultra S5 Surface 128GB 2022, Sliver',        price: '$1,729.00', shipping: 'FREE SHIPPING', stock: 'Contact' },
];

function Stars({ count }) {
  return (
    <div className="cp-stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={s <= count ? 'cp-star filled' : 'cp-star'}>★</span>
      ))}
    </div>
  );
}

function Countdown() {
  const [time, setTime] = useState({ d: 0, h: 9, m: 31, s: 15 });
  useEffect(() => {
    const id = setInterval(() => {
      setTime(t => {
        let { d, h, m, s } = t;
        s--; if (s < 0) { s = 59; m--; }
        if (m < 0) { m = 59; h--; }
        if (h < 0) { h = 23; d--; }
        if (d < 0) d = 0;
        return { d, h, m, s };
      });
    }, 1000);
    return () => clearInterval(id);
  }, []);
  const pad = n => String(Math.max(0, n)).padStart(2, '0');
  return (
    <div className="cp-countdown">
      <p className="cp-hurry">HURRY UP! PROMOTION WILL EXPIRES IN</p>
      <div className="cp-timer">
        {[{ v: time.d, u: 'd' }, { v: time.h, u: 'h' }, { v: time.m, u: 'm' }, { v: time.s, u: 's' }].map(({ v, u }) => (
          <div key={u} className="cp-timer-box">
            <span className="cp-timer-num">{pad(v)}</span>
            <span className="cp-timer-unit">{u}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function CategoriesPage() {
  const { addToCart, setPage } = useCart();
  const [activeTab, setActiveTab]   = useState('BEST SELLER');
  const [quickView, setQuickView]   = useState(null);
  const [toast, setToast]           = useState(null);

  function handleAdd(p) {
    addToCart({ ...p, img: p.img, desc: 'Premium electronics product.' });
    setToast(p);
  }

  return (
    <div className="cp-page">

      {/* ══ 0. HERO SECTION: Sidebar + Slider + Right Banners ══ */}
      <div className="cp-hero-outer">

        {/* Left Sidebar */}
        <aside className="cp-hero-sidebar">
          <p className="cp-sale-tag">SALE 40% OFF</p>
          <ul className="cp-sidebar-list">
            {['Laptops','PC & Computers','Cell Phones','Tablets','Gaming & VR','Networking','Cameras','Sounds','Office','Storage, USB','Accessories','Clearance'].map(link => (
              <li key={link} className="cp-sidebar-item">{link}</li>
            ))}
          </ul>
        </aside>

        {/* Center: Hero Slider + Mini Cards */}
        <div className="cp-hero-center">
          <div className="cp-hero-slide">
            <img src={noiseCancelImg} alt="Noise Cancelling Headphone" className="cp-hero-bg" />
            <div className="cp-hero-content">
              <h2 className="cp-hero-title">Noise Cancelling<br /><span>Headphone</span></h2>
              <p className="cp-hero-sub">Boso Over-Ear Headphone<br />Wifi, Voice Assistant,<br />Low Latency Game Mode</p>
              <button className="cp-hero-btn">BUY NOW</button>
            </div>
            <div className="cp-hero-dots">
              <span className="cp-dot" /><span className="cp-dot" /><span className="cp-dot active" />
              <span className="cp-dot-label">3 / 3</span>
            </div>
          </div>

          {/* Mini product cards below slider */}
          <div className="cp-hero-mini-cards">
            <div className="cp-mini-card">
              <div className="cp-mini-card-info">
                <p className="cp-mini-name">Sono Playgo 5</p>
                <p className="cp-mini-price">from <span>$569</span></p>
                <a href="#!" className="cp-mini-link">DISCOVER NOW</a>
              </div>
              <img src={sonoPlaygoImg} alt="Sono Playgo 5" className="cp-mini-img" />
            </div>
            <div className="cp-mini-card cp-mini-card-dark">
              <div className="cp-mini-card-info">
                <p className="cp-mini-name-light">Logitek Bluetooth</p>
                <p className="cp-mini-highlight">Keyboard</p>
                <p className="cp-mini-desc">Best for all device</p>
              </div>
              <img src={logitekImg} alt="Logitek Keyboard" className="cp-mini-img" />
            </div>
          </div>
        </div>

        {/* Right Banners */}
        <div className="cp-hero-right">
          <div className="cp-right-banner cp-right-banner-light">
            <div className="cp-right-banner-text">
              <p className="cp-right-brand">XOMIA</p>
              <h3 className="cp-right-title">Sport Water<br />Resistance<br />Watch</h3>
              <button className="cp-right-btn">SHOP NOW</button>
            </div>
            <img src={xomiaWatchImg} alt="Xomia Watch" className="cp-right-img" />
          </div>
          <div className="cp-right-banner cp-right-banner-dark">
            <div className="cp-right-banner-text">
              <h3 className="cp-right-title-dark">OKODO<br />HERO 11+<br />BLACK</h3>
              <p className="cp-right-from">FROM</p>
              <p className="cp-right-price">$169</p>
            </div>
            <img src={okodoHeroImg} alt="Okodo Hero" className="cp-right-img-dark" />
          </div>
        </div>
      </div>
      <div className="cp-brands-cats-row">
        <div className="cp-brands-section">
          <div className="cp-section-header">
            <h3 className="cp-section-title">FEATURED BRANDS</h3>
            <a href="#!" className="cp-view-all">View All</a>
          </div>
          <div className="cp-brands-grid">
            {brands.map(b => (
              <div key={b.name} className="cp-brand-item">
                <img src={b.img} alt={b.name} className="cp-brand-img" />
              </div>
            ))}
          </div>
        </div>
        <div className="cp-topcats-section">
          <div className="cp-section-header">
            <h3 className="cp-section-title">TOP CATEGORIES</h3>
            <a href="#!" className="cp-view-all">View All</a>
          </div>
          <div className="cp-topcats-grid">
            {topCategories.map(c => (
              <div key={c.name} className="cp-topcat-item">
                <img src={c.img} alt={c.name} className="cp-topcat-img" />
                <p className="cp-topcat-name">{c.name}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ══ 2. DEALS OF THE DAY + SIDE BANNERS ══ */}
      <div className="cp-deals-outer">

        {/* Deal */}
        <div className="cp-deal-section">
          <div className="cp-deal-header">
            <h3 className="cp-deal-title">DEALS OF THE DAY</h3>
          </div>
          <div className="cp-deal-body">
            <div className="cp-deal-thumbs">
              {[xiaomiImg, xiaomiImg, xiaomiImg].map((img, i) => (
                <img key={i} src={img} alt="thumb" className="cp-deal-thumb" />
              ))}
            </div>
            <div className="cp-deal-main-img">
              <span className="cp-deal-save">SAVE<br />$199.00</span>
              <img src={xiaomiImg} alt="Xioma Redmi" className="cp-deal-img" />
            </div>
            <div className="cp-deal-info">
              <p className="cp-deal-reviews">(12)</p>
              <h3 className="cp-deal-name">Xioma Redmi Note 11 Pro 256GB 2023, Black Smartphone</h3>
              <div className="cp-deal-price-row">
                <span className="cp-deal-price">$569.00</span>
                <span className="cp-deal-old">$759.00</span>
              </div>
              <ul className="cp-deal-specs">
                <li>Intel LGA 1700 Socket: Supports 13th & 12th Gen Intel Core</li>
                <li>DDR5 Compatible: 4*SMD DIMMs with XMP 3.0 Memory</li>
                <li>Commanding Power Design: Twin 16+1+2 Phases Digital VRM</li>
              </ul>
              <div className="cp-deal-tags">
                <span className="cp-deal-tag-free">FREE SHIPPING</span>
                <span className="cp-deal-tag-gift">FREE GIFT</span>
              </div>
              <Countdown />
              <div className="cp-deal-progress-wrap">
                <div className="cp-deal-progress-bar">
                  <div className="cp-deal-progress-fill" style={{ width: '35%' }} />
                </div>
                <p className="cp-deal-sold">Sold: <strong>26/75</strong></p>
              </div>
            </div>
          </div>
        </div>

        {/* Side banners */}
        <div className="cp-side-banners">
          <div className="cp-side-banner cp-side-banner-dark">
            <div className="cp-side-banner-text">
              <p className="cp-side-sale">SALE</p>
              <p className="cp-side-pct">50%</p>
            </div>
            <img src={joystickImg} alt="Gaming" className="cp-side-banner-img" />
          </div>
          <div className="cp-side-banner cp-side-banner-green">
            <img src={ipadImg} alt="iPad" className="cp-side-banner-img cp-side-full-img" />
          </div>
        </div>
      </div>

      {/* ══ 3. FREE SHIPPING BANNER ══ */}
      <div className="cp-free-banner">
        <span className="cp-free-star">⭐</span>
        Member get <span className="cp-free-highlight">FREE SHIPPING*</span> with no order minimum!. *Restriction apply
        <a href="#!" className="cp-free-trial">Try free 30-days trial!</a>
      </div>

      {/* ══ 4. BEST SELLER TABS ══ */}
      <div className="cp-tabs-section">
        <div className="cp-tabs-header">
          <div className="cp-tabs">
            {['BEST SELLER', 'NEW IN', 'POPULAR'].map(t => (
              <button
                key={t}
                className={`cp-tab ${activeTab === t ? 'active' : ''}`}
                onClick={() => setActiveTab(t)}
              >
                {t}
              </button>
            ))}
          </div>
          <a href="#!" className="cp-view-all-link">View All</a>
        </div>

        <div className="cp-bs-grid">
          {bestSellerProducts.map(p => (
            <div key={p.id} className="cp-bs-card">
              <div className="cp-bs-img-wrap">
                {p.save && <span className="cp-bs-save">SAVE<br />{p.save}</span>}
                <img src={p.img} alt={p.name} className="cp-bs-img" />
              </div>
              <div className="cp-bs-info">
                {p.reviews && <p className="cp-bs-reviews">({p.reviews})</p>}
                <p className="cp-bs-name">{p.name}</p>
                <div className="cp-bs-price-row">
                  <span className={`cp-bs-price ${p.oldPrice ? 'pink' : ''}`}>{p.price}</span>
                  {p.oldPrice && <span className="cp-bs-old">{p.oldPrice}</span>}
                </div>
                <div className="cp-bs-tags">
                  {p.shipping && <span className="cp-bs-tag-ship">{p.shipping}</span>}
                  {p.gift     && <span className="cp-bs-tag-gift">{p.gift}</span>}
                </div>
                {p.stock && <p className={`cp-bs-stock ${p.stock === 'Out of stock' ? 'out' : p.stock === 'PRE - ORDER' ? 'pre' : ''}`}>{p.stock}</p>}
                {p.variants && (
                  <div className="cp-bs-variants">
                    {p.variants.map((v, i) => (
                      <img key={i} src={v} alt="variant" className="cp-bs-variant-img" />
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ══ 5. BRAND NEW FOR YOU ══ */}
      <div className="cp-brandnew-section">
        <h2 className="cp-brandnew-title">BRAND NEW FOR YOU</h2>
        <div className="cp-brandnew-grid">
          {brandNewItems.map((item, i) => (
            <div key={i} className="cp-brandnew-card">
              <div className="cp-brandnew-img-wrap">
                <img src={item.img} alt={item.title} className="cp-brandnew-img" />
              </div>
              <p className="cp-brandnew-name">{item.title}</p>
              <p className="cp-brandnew-desc">{item.desc}</p>
              <button className="cp-brandnew-btn">SHOP NOW</button>
            </div>
          ))}
        </div>
      </div>

      {/* ══ 6. TOP CELLPHONES & TABLETS ══ */}
      <div className="cp-topcell-section">
        <div className="cp-section-header">
          <h2 className="cp-topcell-title">TOP CELLPHONES & TABLETS</h2>
          <a href="#!" className="cp-view-all">View All</a>
        </div>
        <img src={topCellphoneImg} alt="Top Cellphones & Tablets" className="cp-topcell-img" />

        {/* Cell phone product cards */}
        <div className="cp-cell-grid">
          {cellPhoneProducts.map(p => (
            <div key={p.id} className="cp-bs-card">
              <div className="cp-bs-img-wrap">
                {p.save  && <span className="cp-bs-save">SAVE<br />{p.save}</span>}
                {p.badge && <span className="cp-cell-badge">{p.badge}</span>}
                <img src={p.img} alt={p.name} className="cp-bs-img" />
              </div>
              <div className="cp-bs-info">
                <p className="cp-bs-name">{p.name}</p>
                <div className="cp-bs-price-row">
                  <span className={`cp-bs-price ${p.oldPrice ? 'pink' : ''}`}>{p.price}</span>
                  {p.oldPrice && <span className="cp-bs-old">{p.oldPrice}</span>}
                </div>
                <div className="cp-bs-tags">
                  {p.shipping && <span className="cp-bs-tag-ship">{p.shipping}</span>}
                  {p.gift     && <span className="cp-bs-tag-gift">{p.gift}</span>}
                </div>
                {p.stock && <p className={`cp-bs-stock ${p.stock === 'Out of stock' ? 'out' : p.stock === 'PRE - ORDER' ? 'pre' : ''}`}>{p.stock}</p>}
              </div>
            </div>
          ))}
        </div>
      </div>

      {quickView && (
        <QuickViewModal
          product={{ ...quickView, cat: 'Electronics', desc: 'Premium electronics product.' }}
          onClose={() => setQuickView(null)}
          onAddedToCart={p => setToast(p)}
        />
      )}
      {toast && (
        <CartToast
          product={toast}
          onClose={() => setToast(null)}
          onViewCart={() => { setToast(null); setPage('cart'); }}
        />
      )}
    </div>
  );
}
